 1	import { ResourceLink, useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 2	import {
 3	  FormGroup,
 4	  FormHelperText,
 5	  FormSelect,
 6	  FormSelectOption,
 7	  HelperText,
 8	  HelperTextItem,
 9	} from '@patternfly/react-core';
10	import * as React from 'react';
11	import { Issuer } from './types'; // You will need to define this type similarly to Gateway.
12	import { useTranslation } from 'react-i18next';
13	
14	interface IssuerSelectProps {
15	  selectedIssuer: Issuer;
16	  onChange: (updated: Issuer) => void;
17	}
18	
19	const IssuerSelect: React.FC<IssuerSelectProps> = ({ selectedIssuer, onChange }) => {
20	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
21	  const [issuers, setIssuers] = React.useState([]);
22	  const gvk = { group: 'cert-manager.io', version: 'v1', kind: 'Issuer' };
23	
24	  const clusterIssuerResource = {
25	    groupVersionKind: gvk,
26	    isList: true,
27	  };
28	
29	  const [clusterIssuerData, clusterIssuerLoaded, clusterIssuerError] =
30	    useK8sWatchResource(clusterIssuerResource);
31	
32	  React.useEffect(() => {
33	    if (clusterIssuerLoaded && !clusterIssuerError && Array.isArray(clusterIssuerData)) {
34	      setIssuers(
35	        clusterIssuerData.map((clusterIssuer) => ({
36	          name: clusterIssuer.metadata.name,
37	          namespace: clusterIssuer.metadata.namespace,
38	        })),
39	      );
40	    }
41	  }, [clusterIssuerData, clusterIssuerLoaded, clusterIssuerError]);
42	
43	  const handleIssuerChange = (event: React.FormEvent<HTMLSelectElement>) => {
44	    const [namespace, name] = event.currentTarget.value.split('/');
45	    onChange({ ...selectedIssuer, name, namespace });
46	  };
47	
48	  return (
49	    <>
50	      <FormGroup label={t('Issuer API Target Reference')} isRequired fieldId="clusterissuer-select">
51	        <FormSelect
52	          id="clusterissuer-select"
53	          value={`${selectedIssuer.namespace}/${selectedIssuer.name}`}
54	          onChange={handleIssuerChange}
55	          aria-label={t('Select Issuer')}
56	        >
57	          <FormSelectOption
58	            key="placeholder"
59	            value=""
60	            label={t('Select an Issuer')}
61	            isPlaceholder
62	          />
63	          {issuers.map((clusterIssuer, index) => (
64	            <FormSelectOption
65	              key={index}
66	              value={`${clusterIssuer.namespace}/${clusterIssuer.name}`}
67	              label={`${clusterIssuer.namespace}/${clusterIssuer.name}`}
68	            />
69	          ))}
70	        </FormSelect>
71	        <FormHelperText>
72	          <HelperText>
73	            <HelperTextItem>
74	              {t(
75	                'Issuer: Reference to the issuer for the created certificate. To create an additional Issuer go to',
76	              )}{' '}
77	              <ResourceLink
78	                groupVersionKind={gvk}
79	                title="Create an Issuer"
80	                hideIcon={true}
81	                inline={true}
82	                displayName="here"
83	              />
84	            </HelperTextItem>
85	          </HelperText>
86	        </FormHelperText>
87	      </FormGroup>
88	    </>
89	  );
90	};
91	
92	export default IssuerSelect;

